mapper.insert:

    SELECT
        CONCAT('MENU', LPAD(IFNULL(MAX(CAST(SUBSTRING(MENU_ID, 5) AS UNSIGNED)), 0) +1, 8, '0'))
    FROM TB_MENU

INSERT INTO TB_MENU
(
    MENU_ID
    , MENU_PARENT_ID
    , MENU_NAME
    , MENU_URL
    , USE_YN
    , CREATE_USER_ID
    , UPDATE_USER_ID
    , CREATE_DATE
    , UPDATE_DATE
)VALUES(
    #{vo.menuId}
    , #{vo.menuParentId}
    , #{vo.menuName}
    , #{vo.menuUrl}
    , #{vo.useYn}
    , #{vo.createUserId}
    , #{vo.updateUserId}
    , NOW()
    , NOW()
)
